function loadState(){
  try {
    const raw = localStorage.getItem(STORE_KEY);
    if(raw){
      const s = JSON.parse(raw);
      return {
        basePrompts: s.basePrompts || clone(BUNDLED_BASE),
        hair: s.hair || clone(BUNDLED_HAIR),
        poses: s.poses || clone(BUNDLED_POSES),
        envs: s.envs || clone(BUNDLED_ENVS),
        models: s.models || deepCloneModels(BUNDLED_MODELS)
      };
    }
  } catch(e){}
  return {
    basePrompts: clone(BUNDLED_BASE),
    hair: clone(BUNDLED_HAIR),
    poses: clone(BUNDLED_POSES),
    envs: clone(BUNDLED_ENVS),
    models: deepCloneModels(BUNDLED_MODELS)
  };
}
function deepCloneModels(m){ return JSON.parse(JSON.stringify(m)); }
function clone(x){ return JSON.parse(JSON.stringify(x)); }
function saveState(){
  localStorage.setItem(STORE_KEY, JSON.stringify({
    basePrompts: DATA.basePrompts,
    hair: DATA.hair,
    poses: DATA.poses,
    envs: DATA.envs,
    models: DATA.models
  }));
}

const DATA = loadState();

// ============================================================
// HELPERS
// ============================================================
function el(id){ return document.getElementById(id); }
function esc(s){ return String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function rand(arr){ return arr[Math.floor(Math.random()*arr.length)]; }
function weightedPick(items){
  const total = items.reduce((s,x)=>s+x.weight,0);
  let r = Math.random()*total;
  for(const item of items){ r -= item.weight; if(r<=0) return item; }
  return items[0];
}

