// CURRENT FILTER STATE
// ============================================================
let currentAge = 'Younger';
let microMode = 'On';
let currentMode = 'random';
const DIMS = ['model','hair','pose','env'];
const dimState = {model:new Set(), hair:new Set(), pose:new Set(), env:new Set()};

// ============================================================
// POOL FUNCTIONS
// ============================================================
function genderFamilyFromGender(g){
  const s = (g||'').toLowerCase();
  return (s.includes('boy') || s.includes('male')) ? 'Male' : 'Female';
}

function getModelPool(){
  const gf = genderFamilyFromGender(el('genderSelect').value === 'All' ? 'Girl' : el('genderSelect').value);
  const arr = (DATA.models[gf] || {})[currentAge] || [];
  return arr.filter(x => x.enabled !== false);
}

function getHairPool(){
  const gv = el('genderSelect').value;
  const gf = genderFamilyFromGender(gv === 'All' ? 'Girl' : gv);
  return DATA.hair.filter(x => x.enabled !== false && (x.genderFamily === gf || x.genderFamily === 'Any') && (x.ageBucket === currentAge || x.ageBucket === 'Any'));
}

function getPosePool(){
  return DATA.poses.filter(x => x.enabled !== false && (x.ageBucket === currentAge || x.ageBucket === 'Any'));
}

function getEnvPool(){
  return DATA.envs.filter(x => x.enabled !== false);
}

// ============================================================
// MULTI-SELECT DROPDOWNS
// ============================================================
function buildMultiDropdown(dim){
  let pool = [];
  if(dim === 'model') pool = getModelPool();
  else if(dim === 'hair') pool = getHairPool();
  else if(dim === 'pose') pool = getPosePool();
  else if(dim === 'env') pool = getEnvPool();

  const query = (el('search-'+dim)||{value:''}).value.toLowerCase();
  const filtered = pool.filter(x => !query || (x.identifier||'').toLowerCase().includes(query) || (x.prompt||'').toLowerCase().includes(query));
  const list = el('list-'+dim);
  list.innerHTML = filtered.map(x => {
    const id = x.id || x._id || x.identifier;
    const checked = dimState[dim].has(id) ? 'checked' : '';
    return `<div class="multi-dropdown-item">
      <input type="checkbox" id="chk-${dim}-${esc(id)}" ${checked} onchange="toggleItem('${dim}','${esc(id)}',this.checked)">
      <label for="chk-${dim}-${esc(id)}">${esc(x.identifier)}</label>
    </div>`;
  }).join('');
  updateDimTrigger(dim);
}

function toggleItem(dim, id, val){
  if(val) dimState[dim].add(id); else dimState[dim].delete(id);
  updateDimTrigger(dim);
}

function updateDimTrigger(dim){
  const count = dimState[dim].size;
  el('count-'+dim).textContent = count;
  if(count === 0){ el('label-'+dim).textContent = {model:'Select models…',hair:'Select hair styles…',pose:'Select poses…',env:'Select environments…'}[dim]; }
  else if(count === 1){ el('label-'+dim).textContent = '1 selected'; }
  else { el('label-'+dim).textContent = count+' selected'; }
  const note = el('note-'+dim);
  const minReq = 1;
  if(count > 0 && count < minReq){
    note.textContent = 'Select at least 1 item';
    note.className = 'min-note error';
  } else {
    note.textContent = count > 0 ? count+' selected' : '';
    note.className = 'min-note';
  }
  validateMinimum();
}

function validateMinimum(){
  const activeDims = DIMS.filter(d => dimState[d].size >= 1);
  const btn = el('generateBtn');
  if(currentMode === 'original'){
    btn.disabled = false; btn.style.opacity = '1'; return;
  }
  if(activeDims.length < 2){ btn.disabled = true; btn.style.opacity = '0.5'; }
  else { btn.disabled = false; btn.style.opacity = '1'; }
}

function selectAll(dim){
  let pool = [];
  if(dim === 'model') pool = getModelPool();
  else if(dim === 'hair') pool = getHairPool();
  else if(dim === 'pose') pool = getPosePool();
  else if(dim === 'env') pool = getEnvPool();
  pool.forEach(x => { const id = x.id||x._id||x.identifier; dimState[dim].add(id); });
  buildMultiDropdown(dim);
}
function clearAll(dim){ dimState[dim].clear(); buildMultiDropdown(dim); }

function toggleDropdown(dim){
  const dropdown = el('dropdown-'+dim);
  const trigger = el('trigger-'+dim);
  const isOpen = dropdown.classList.contains('open');
  DIMS.forEach(d => { el('dropdown-'+d).classList.remove('open'); el('trigger-'+d).classList.remove('open'); });
  if(!isOpen){ dropdown.classList.add('open'); trigger.classList.add('open'); buildMultiDropdown(dim); const s=el('search-'+dim); if(s)s.focus(); }
}

document.addEventListener('click', e => {
  DIMS.forEach(dim => {
    const wrap = el('wrap-'+dim);
    if(wrap && !wrap.contains(e.target)){ el('dropdown-'+dim).classList.remove('open'); el('trigger-'+dim).classList.remove('open'); }
  });
});

// ============================================================
// FILTERS
// ============================================================
function initFilters(){
  const genders = ['All','Baby Girl','Baby Boy','Girl','Boy'];
  el('genderSelect').innerHTML = genders.map(g=>`<option>${esc(g)}</option>`).join('');
  refreshCategorySelect();
  refreshSourcePromptSelect();
}

function refreshCategorySelect(){
  const gv = el('genderSelect').value;
  const cats = [...new Set(DATA.basePrompts.filter(x => gv==='All'||x.gender===gv).filter(x=>x.ageBucket===currentAge).map(x=>x.category))].sort();
  const prev = el('categorySelect').value;
  el('categorySelect').innerHTML = ['All',...cats].map(c=>`<option>${esc(c)}</option>`).join('');
  if(cats.includes(prev)) el('categorySelect').value = prev;
  refreshSourcePromptSelect();
}

function refreshSourcePromptSelect(){
  const gv = el('genderSelect').value;
  const cv = el('categorySelect').value;
  const rows = DATA.basePrompts.filter(x=>(gv==='All'||x.gender===gv)&&(x.ageBucket===currentAge)&&(cv==='All'||x.category===cv));
  el('sourcePromptSelect').innerHTML = rows.map((x,i)=>`<option value="${i}">[${esc(x.gender)}] ${esc(x.identifier||('Row '+(i+1)))}</option>`).join('');
  rebuildAllDropdowns();
  updateMetaText();
}

function rebuildAllDropdowns(){
  DIMS.forEach(dim => {
    let pool = [];
    if(dim==='model') pool = getModelPool();
    else if(dim==='hair') pool = getHairPool();
    else if(dim==='pose') pool = getPosePool();
    else if(dim==='env') pool = getEnvPool();
    const validIds = new Set(pool.map(x=>x.id||x._id||x.identifier));
    [...dimState[dim]].filter(id=>!validIds.has(id)).forEach(id=>dimState[dim].delete(id));
    buildMultiDropdown(dim);
  });
  validateMinimum();
}

function updateMetaText(){
  el('metaText').textContent = DATA.basePrompts.length+' base prompts · '+DATA.hair.length+' hair · '+DATA.poses.length+' poses';
}

// ============================================================
// PROMPT BUILDING
// ============================================================
function pickExpressionProfile(){
  const mode = el('expressionModeSelect').value;
  const key = mode==='Playful Heavy'?'playful':mode==='Calm Heavy'?'calm':mode==='Confident Heavy'?'confident':'balanced';
  return weightedPick(EXPRESSION_PROFILES[key]);
}

function pickMicro(profileName){
  if(microMode==='Off') return null;
  const pool = MICRO_MAP[profileName];
  if(!pool) return null;
  return {gaze:rand(pool.gaze),hands:rand(pool.hands),weight:rand(pool.weight),expression:rand(pool.expression)};
}

function openingLine(base){
  const g = (base.gender||'').toLowerCase();
  if(g.includes('boy')||g==='male') return 'Generate a photorealistic "FULL LENGTH FRONTAL VIEW" image of ONE boy model wearing the provided garment with 100% accuracy.';
  return 'Generate a photorealistic "FULL LENGTH FRONTAL VIEW" image of ONE girl model wearing the provided garment with 100% accuracy.';
}

function categoryStyling(category){
  const c=(category||'').toLowerCase();
  if(c.includes('top')) return 'CATEGORY & STYLING:\n\nTOP must remain fully untucked to show complete length and silhouette.\n\nStyled with bottoms that complement the garment.\n\nStyled with fashion footwear that complements the look.';
  if(c.includes('bottom')) return 'CATEGORY & STYLING:\n\nBOTTOM must be clearly visible with full waistband and full length.\n\nStyled with a clean minimal top that does not distract from the bottom garment.\n\nStyled with fashion footwear that complements the look.';
  if(c.includes('dress')) return 'CATEGORY & STYLING:\n\nDress must be worn as a single complete garment with full silhouette clearly visible.\n\nNo layering or additional garments.\n\nStyled with fashion footwear that complements the look.';
  if(c.includes('co-ord')||c.includes('coord')||c.includes('set')||c.includes('sleepwear')||c.includes('sportswear')) return 'CATEGORY & STYLING:\n\nTop and bottom must be worn together as a complete set.\n\nBoth pieces must remain fully visible.\n\nTop must remain fully untucked unless explicitly designed otherwise.\n\nStyled with fashion footwear or barefoot as appropriate.';
  return 'CATEGORY & STYLING:\n\nGarment must be styled in a clean minimal way that preserves full visibility.\n\nStyled with appropriate footwear.';
}

function buildPrompt(base, model, hair, pose, expression, micro, env){
  const blocks = [
    openingLine(base),
    '',
    'GARMENT ACCURACY STRICT:',
    'Replicate the garment exactly as in the input including color, texture, stitching, silhouette, proportions and any graphics or text placement. No approximation.',
    '',
    categoryStyling(base.category),
    '',
    'MODEL — '+model.identifier,
    '',
    model.ageHeight,
    '',
    model.features,
    '',
    'Maintain correct body proportions for age.',
    '',
    currentAge==='Younger'?'Warm, natural, childlike presence with soft candid expression. Bright, playful energy with spontaneous expressions.':'Warm, natural, childlike presence with soft candid expression. Gentle, confident energy with a natural and relaxed expression.',
    '',
    'HAIR — '+hair.identifier,
    '',
    hair.prompt,
    '',
    'POSE — '+pose.identifier,
    '',
    pose.prompt,
    '',
    currentAge==='Younger'?'Pose must feel spontaneous, playful and full of childlike warmth — natural, candid and never staged.':'Pose must feel natural, relaxed and softly confident — maintaining warmth and childlike authenticity.',
    '',
    'EXPRESSION PROFILE — '+expression.name,
    '',
    expression.text
  ];
  if(micro){ blocks.push('','MICRO VARIATION:','',micro.gaze,'',micro.hands,'',micro.weight,'',micro.expression); }
  const customOverride = el('customEnvOverride').value.trim();
  const envBg = customOverride || env.prompt;
  blocks.push(
    '','BACKGROUND:','',envBg,
    '','LIGHTING:','',customOverride?'Use environment-consistent lighting from the provided override.':env.lighting,
    '','SHADOWS:','',customOverride?'Use environment-consistent shadows.':env.shadows,
    '','CAMERA:','',customOverride?'Use environment-consistent camera.':env.camera,
    '','COMPOSITION:','','Full length image. Entire model visible from head to toe. Clean, open framing with outfit as focal point. One model only.',
    '','MOOD:','','Warm, soft, childlike and emotionally engaging. Consistent with premium kidswear brand aesthetic.',
    '','NEGATIVE PROMPT:','','No extra people, no props, no clutter. No distortion or incorrect anatomy. Do not modify garment in any way. NO TUCKS.'
  );
  return blocks.join('\n').replace(/\n{3,}/g,'\n\n').trim();
}

// ============================================================
// PICK FROM DIM
// ============================================================
function pickFromDim(dim){
  let pool = [];
  if(dim==='model') pool = getModelPool();
  else if(dim==='hair') pool = getHairPool();
  else if(dim==='pose') pool = getPosePool();
  else if(dim==='env') pool = getEnvPool();
  const selected = [...dimState[dim]];
  if(!selected.length) return pool[Math.floor(Math.random()*pool.length)] || null;
  const id = rand(selected);
  return pool.find(x=>(x.id||x._id||x.identifier)===id) || null;
}

function getFallback(dim){
  let pool = [];
  if(dim==='model') pool = getModelPool();
  else if(dim==='hair') pool = getHairPool();
  else if(dim==='pose') pool = getPosePool();
  else if(dim==='env') pool = getEnvPool();
  return pool.length ? rand(pool) : null;
}

// ============================================================
// GENERATE
// ============================================================
let generated = [];

function generate(){
  const gv = el('genderSelect').value;
  const cv = el('categorySelect').value;
  const srcIdx = parseInt(el('sourcePromptSelect').value) || 0;
  const filteredBases = DATA.basePrompts.filter(x=>(gv==='All'||x.gender===gv)&&(x.ageBucket===currentAge)&&(cv==='All'||x.category===cv));

  if(!filteredBases.length){ alert('No base prompts match this filter.'); return; }

  generated = [];
  if(currentMode==='original'){
    const base = filteredBases[srcIdx] || filteredBases[0];
    for(let i=0;i<10;i++){
      generated.push({variation:i+1,mode:'Original Only',gender:base.gender,category:base.category,model:'-',hair:'-',pose:'-',env:'-',expression:'-',prompt:base.prompt});
    }
    renderCards(); return;
  }

  const activeDims = DIMS.filter(d=>dimState[d].size>=1);
  if(activeDims.length < 2){ alert('Please select at least 1 item in at least 2 different dimensions.'); return; }

  const seen = new Set();
  let attempts = 0;
  while(generated.length < 10 && attempts < 250){
    attempts++;
    const base = filteredBases[attempts % filteredBases.length];
    const model = dimState.model.size ? pickFromDim('model') : getFallback('model');
    const hair = dimState.hair.size ? pickFromDim('hair') : getFallback('hair');
    const pose = dimState.pose.size ? pickFromDim('pose') : getFallback('pose');
    const envItem = dimState.env.size ? pickFromDim('env') : getFallback('env');
    if(!model||!hair||!pose||!envItem) continue;
    const expression = pickExpressionProfile();
    const micro = pickMicro(expression.name);
    const key = [base.gender,base.category,model.id||model.identifier,hair.id||hair.identifier,pose.id||pose.identifier,envItem.id||envItem.identifier,expression.name].join('||');
    if(seen.has(key)&&attempts<200) continue;
    seen.add(key);
    generated.push({
      variation: generated.length+1,
      mode:'Randomizer',
      gender:base.gender,
      category:base.category,
      model:model.identifier,
      hair:hair.identifier,
      pose:pose.identifier,
      env:envItem.identifier,
      expression:expression.name,
      prompt:buildPrompt(base,model,hair,pose,expression,micro,envItem)
    });
  }
  renderCards();
}

function renderCards(){
  const grid = el('cardsGrid');
  const empty = el('emptyState');
  const header = el('resultsHeader');
  if(!generated.length){ grid.innerHTML=''; empty.style.display='flex'; header.style.display='none'; return; }
  empty.style.display='none'; header.style.display='flex';
  el('resultsCount').textContent = generated.length+' prompts generated';
  grid.innerHTML = generated.map((item,idx)=>`
    <div class="prompt-card" style="animation-delay:${idx*0.04}s">
      <div class="card-header">
        <div class="card-meta">
          <span class="variation-num">${String(item.variation).padStart(2,'0')}</span>
          <span class="mode-badge ${item.mode==='Randomizer'?'random':'original'}">${esc(item.mode)}</span>
          <span class="text-sm text-muted">${esc(item.category)}</span>
        </div>
        <button class="btn btn-ghost copy-btn" onclick="copySingle(${idx})">Copy</button>
      </div>
      <div class="card-attributes">
        <div class="attr-cell"><div class="attr-label">Gender</div><div class="attr-value" title="${esc(item.gender)}">${esc(item.gender)}</div></div>
        <div class="attr-cell"><div class="attr-label">Model</div><div class="attr-value" title="${esc(item.model)}">${esc(item.model)}</div></div>
        <div class="attr-cell"><div class="attr-label">Hair</div><div class="attr-value" title="${esc(item.hair)}">${esc(item.hair)}</div></div>
        <div class="attr-cell"><div class="attr-label">Pose</div><div class="attr-value" title="${esc(item.pose)}">${esc(item.pose)}</div></div>
        <div class="attr-cell"><div class="attr-label">Environment</div><div class="attr-value" title="${esc(item.env)}">${esc(item.env)}</div></div>
        <div class="attr-cell"><div class="attr-label">Expression</div><div class="attr-value" title="${esc(item.expression)}">${esc(item.expression)}</div></div>
      </div>
      <div class="card-body">
        <details open><summary>Full Prompt</summary><pre class="prompt-text">${esc(item.prompt)}</pre></details>
      </div>
    </div>`).join('');
}

function copySingle(idx){ if(generated[idx]) navigator.clipboard.writeText(generated[idx].prompt); }
function copyAll(){ if(!generated.length){alert('Nothing to copy');return;} navigator.clipboard.writeText(generated.map(x=>x.prompt).join('\n\n---\n\n')); }
function downloadCSV(){
  if(!generated.length){alert('Nothing to download');return;}
  const hdr = ['variation','mode','gender','category','model','hair','pose','env','expression','prompt'];
  const rows = [hdr, ...generated.map(r=>hdr.map(k=>`"${String(r[k]||'').replace(/"/g,'""')}"` ))];
  const blob = new Blob([rows.map(r=>r.join(',')).join('\n')],{type:'text/csv;charset=utf-8;'});
  const a = document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='babyshop_prompts.csv';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
}

