function getResArray(type){
  if(type==='basePrompts') return DATA.basePrompts;
  if(type==='models'){
    const out=[];
    Object.entries(DATA.models).forEach(([gf,group])=>Object.entries(group).forEach(([ab,arr])=>arr.forEach(item=>out.push({...item,_gf:gf,_ab:ab}))));
    return out;
  }
  if(type==='hair') return DATA.hair;
  if(type==='poses') return DATA.poses;
  if(type==='environments') return DATA.envs;
  return [];
}

function renderResources(){
  const type = el('resourceTypeSelect').value;
  const gf = el('resourceGenderFilter').value;
  const af = el('resourceAgeFilter').value;
  const query = (el('resourceSearch')||{value:''}).value.toLowerCase();
  const activeOnly = (el('showActiveOnly')||{checked:false}).checked;

  const arr = getResArray(type);
  const items = arr.filter(x=>{
    const gMatch = gf==='All'||x.genderFamily===gf||x._gf===gf||x.gender===gf||gf==='All';
    const aMatch = af==='All'||x.ageBucket===af||x._ab===af;
    const qMatch = !query||(x.identifier||'').toLowerCase().includes(query)||(x.prompt||'').toLowerCase().includes(query)||(x.features||'').toLowerCase().includes(query);
    const enMatch = !activeOnly||x.enabled!==false;
    return (gf==='All'||gMatch)&&(af==='All'||aMatch)&&qMatch&&enMatch;
  });

  el('libCount').textContent = items.length+' visible · '+arr.length+' total in this type';

  const tbody = items.map(x=>{
    const isLocked = x.locked===true;
    const isEnabled = x.enabled!==false;
    const pri = x.priority||'Normal';
    const promptText = x.prompt||x.features||'';
    const gfShow = x.genderFamily||x._gf||x.gender||'—';
    const ageShow = x.ageBucket||x._ab||'—';
    return `<tr class="${isEnabled?'':'disabled-row'}" data-id="${esc(x.id||x._id||x.identifier)}" data-type="${esc(type)}">
      <td class="col-id">
        <div class="view-mode">${esc(x.identifier)}</div>
        <input type="text" class="cell-edit edit-identifier" value="${esc(x.identifier)}" style="display:none">
      </td>
      <td class="col-gf">
        <div class="view-mode">${esc(gfShow)}</div>
        <input type="text" class="cell-edit edit-gf" value="${esc(gfShow)}" style="display:none">
      </td>
      <td class="col-age">
        <div class="view-mode">${esc(ageShow)}</div>
        <select class="cell-edit edit-age" style="display:none">
          <option value="Younger" ${ageShow==='Younger'?'selected':''}>Younger</option>
          <option value="Older" ${ageShow==='Older'?'selected':''}>Older</option>
          <option value="Any" ${ageShow==='Any'?'selected':''}>Any</option>
        </select>
      </td>
      <td class="col-prompt">
        <div class="view-mode" style="font-family:var(--font-mono);font-size:11px;max-height:60px;overflow:hidden;text-overflow:ellipsis;white-space:pre-wrap;color:var(--ink-3)">${esc(promptText.substring(0,180))}${promptText.length>180?'…':''}</div>
        <textarea class="cell-edit edit-prompt" style="display:none">${esc(promptText)}</textarea>
      </td>
      <td class="col-en"><div class="cb-wrap"><input type="checkbox" ${isEnabled?'checked':''} onchange="toggleEnabled('${esc(type)}','${esc(x.id||x._id||x.identifier)}',this.checked)" ${isLocked?'disabled':''}></div></td>
      <td class="col-lock"><div class="cb-wrap lock-cb"><input type="checkbox" ${isLocked?'checked':''} onchange="toggleLocked('${esc(type)}','${esc(x.id||x._id||x.identifier)}',this.checked)"></div></td>
      <td class="col-pri">
        <select class="pri-select" onchange="setPriority('${esc(type)}','${esc(x.id||x._id||x.identifier)}',this.value)" ${isLocked?'disabled':''}>
          <option value="Normal" ${pri==='Normal'?'selected':''}>Normal</option>
          <option value="High" ${pri==='High'?'selected':''}>High</option>
          <option value="Low" ${pri==='Low'?'selected':''}>Low</option>
        </select>
      </td>
      <td class="col-act">
        <div class="row-actions">
          <button class="btn-edit-row" onclick="startEdit(this)" ${isLocked?'disabled':''}>Edit</button>
          <button class="btn-save-row" onclick="saveEdit(this,'${esc(type)}','${esc(x.id||x._id||x.identifier)}')">Save</button>
          <button class="btn-del-row" onclick="deleteEntry('${esc(type)}','${esc(x.id||x._id||x.identifier)}')" ${isLocked?'disabled':''}>Delete</button>
        </div>
      </td>
    </tr>`;
  }).join('');

  el('resourcesContainer').innerHTML = `
    <table class="lib-table">
      <colgroup><col class="col-id"><col class="col-gf"><col class="col-age"><col class="col-prompt"><col class="col-en"><col class="col-lock"><col class="col-pri"><col class="col-act"></colgroup>
      <thead><tr><th>Identifier</th><th>Gender/Family</th><th>Age</th><th>Prompt / Info</th><th>Enabled</th><th>Lock</th><th>Priority</th><th>Actions</th></tr></thead>
      <tbody>${tbody}</tbody>
    </table>`;
}

function findItem(type, id){
  const arr = getResArray(type);
  return arr.find(x=>(x.id||x._id||x.identifier)===id);
}

function startEdit(btn){
  const row = btn.closest('tr');
  row.querySelectorAll('.view-mode').forEach(e=>e.style.display='none');
  row.querySelectorAll('.cell-edit').forEach(e=>e.style.display='');
  btn.style.display='none';
  row.querySelector('.btn-save-row').style.display='';
}

function saveEdit(btn, type, id){
  const row = btn.closest('tr');
  const item = findItem(type, id);
  if(!item) return;
  item.identifier = row.querySelector('.edit-identifier').value.trim();
  const gfEl = row.querySelector('.edit-gf');
  if(gfEl) item.genderFamily = gfEl.value;
  const ageEl = row.querySelector('.edit-age');
  if(ageEl) item.ageBucket = ageEl.value;
  const promptEl = row.querySelector('.edit-prompt');
  if(promptEl){ if(type==='models') item.features=promptEl.value; else item.prompt=promptEl.value; }
  saveState(); rebuildAllDropdowns(); renderResources();
}

function toggleEnabled(type, id, val){
  const item = findItem(type, id);
  if(item){ item.enabled = val; }
  saveState(); rebuildAllDropdowns();
}

function toggleLocked(type, id, val){
  const item = findItem(type, id);
  if(item){ item.locked = val; }
  saveState(); renderResources();
}

function setPriority(type, id, val){
  const item = findItem(type, id);
  if(item){ item.priority = val; }
  saveState();
}

function deleteEntry(type, id){
  if(!confirm('Delete this entry? This cannot be undone.')) return;
  if(type==='basePrompts'){ DATA.basePrompts = DATA.basePrompts.filter(x=>(x.id||x.identifier)!==id); }
  else if(type==='hair'){ DATA.hair = DATA.hair.filter(x=>(x.id||x._id||x.identifier)!==id); }
  else if(type==='poses'){ DATA.poses = DATA.poses.filter(x=>(x.id||x._id||x.identifier)!==id); }
  else if(type==='environments'){ DATA.envs = DATA.envs.filter(x=>(x.id||x.identifier)!==id); }
  else if(type==='models'){
    Object.values(DATA.models).forEach(group=>Object.values(group).forEach(arr=>{
      const i = arr.findIndex(x=>x.id===id); if(i>=0) arr.splice(i,1);
    }));
  }
  saveState(); refreshCategorySelect(); rebuildAllDropdowns(); renderResources(); updateMetaText();
}

