function openAddModal(){
  el('modalTitle').textContent = 'Add New Entry';
  el('modalType').value = el('resourceTypeSelect').value;
  el('modalIdentifier').value=''; el('modalCategory').value='';
  el('modalGender').value='Girl'; el('modalAge').value='Younger';
  el('modalPriority').value='Normal'; el('modalEnabled').checked=true;
  el('modalPrompt').value='';
  el('entryModal').classList.add('open');
}
function closeModal(){ el('entryModal').classList.remove('open'); }
function saveModal(){
  const type = el('modalType').value;
  const ident = el('modalIdentifier').value.trim();
  const promptVal = el('modalPrompt').value.trim();
  if(!ident){ alert('Please enter an Identifier.'); return; }
  const gv = el('modalGender').value;
  const av = el('modalAge').value;
  const pv = el('modalPriority').value;
  const ev = el('modalEnabled').checked;
  const catVal = el('modalCategory').value.trim();
  const uid = type+'_new_'+Date.now();

  if(type==='basePrompts'){
    if(!promptVal){ alert('Please enter the prompt.'); return; }
    DATA.basePrompts.push({id:uid,identifier:ident,gender:gv,ageBucket:av,category:catVal||'Other',prompt:promptVal,priority:pv,enabled:ev,locked:false});
  } else if(type==='hair'){
    if(!promptVal){ alert('Please enter the prompt.'); return; }
    DATA.hair.push({id:uid,identifier:ident,genderFamily:gv==='Girl'||gv==='Baby Girl'?'Female':'Male',ageBucket:av,family:catVal||'General',prompt:promptVal,priority:pv,enabled:ev,locked:false});
  } else if(type==='poses'){
    if(!promptVal){ alert('Please enter the prompt.'); return; }
    DATA.poses.push({id:uid,identifier:ident,ageBucket:av,family:catVal||'Frontal',prompt:promptVal,priority:pv,enabled:ev,locked:false});
  } else if(type==='environments'){
    if(!promptVal){ alert('Please enter the environment description.'); return; }
    DATA.envs.push({id:uid,identifier:ident,prompt:promptVal,lighting:'Natural daylight with soft shadows.',shadows:'Soft grounding shadow beneath the model.',camera:'35mm full-frame lens, low camera angle.',priority:pv,enabled:ev,locked:false});
  } else if(type==='models'){
    const gfam = (gv==='Girl'||gv==='Baby Girl')?'Female':'Male';
    if(!DATA.models[gfam]) DATA.models[gfam]={};
    if(!DATA.models[gfam][av]) DATA.models[gfam][av]=[];
    DATA.models[gfam][av].push({id:uid,identifier:ident,ageHeight:'',features:promptVal||'',priority:pv,enabled:ev,locked:false});
  }
  saveState(); refreshCategorySelect(); rebuildAllDropdowns(); renderResources(); updateMetaText();
  el('resourceTypeSelect').value = type;
  closeModal();
}

el('addEntryBtn').addEventListener('click', openAddModal);
el('modalClose').addEventListener('click', closeModal);
el('modalCancel').addEventListener('click', closeModal);
el('modalSave').addEventListener('click', saveModal);
el('entryModal').addEventListener('click', e=>{ if(e.target===el('entryModal')) closeModal(); });

